Custom autograd functions that use `impl_abstract` that give outputs with dynamic shapes are not supported in PT2.

Repro:
```python
import torch
from torch.library import Library, impl
from torch.testing._internal.optests import aot_autograd_check

m = Library("my_custom_library", "DEF")
m.define("custom_op(Tensor input, Tensor lengths) -> Tensor")

class CustomOp(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input, lengths):
        ctx.save_for_backward(input, lengths)
        with torch._C._AutoDispatchBelowAutograd():
            return torch.ops.my_custom_library.custom_op(input, lengths)

    @staticmethod
    def backward(ctx, grad):
        input, lengths = ctx.saved_tensors
        idx = lengths.sum()
        grad_out = torch.zeros_like(input)
        grad_out[:idx] = grad
        return grad_out, None

@impl(m, "custom_op", "CPU")
def custom_op_impl(input, lengths):
    idx = lengths.sum()
    return input[:idx].clone()

@impl(m, "custom_op", "Autograd")
def custom_op_autograd(input, lengths):
    return CustomOp.apply(input, lengths)

@torch.library.impl_abstract("my_custom_library::custom_op")
def custom_op_meta(input, lengths):
    return input.new_empty(torch.library.get_ctx().new_dynamic_size())

def fn(x):
    return torch.ops.my_custom_library.custom_op(x, torch.tensor([1, 1, 1, 1], dtype=torch.int64))

aot_autograd_check(fn, (torch.randn(10, requires_grad=True),), {}, True)
```

